# Get maximum qubit index used
lines = circuit_text.strip().split('\n')
max_qubit = 0
for line in lines:
    parts = line.split()
    gate = parts[0]
    qubits = [int(q) for q in parts[1:]]
    if qubits:
        max_qubit = max(max_qubit, max(qubits))

print(f"Maximum qubit index in original circuit: {max_qubit}")
print(f"Total lines: {len(lines)}")
